// Tuple: return multiple values from a function
fn min_max(list: &[i32]) -> (i32, i32) {
    let mut min = list[0];
    let mut max = list[0];
    for &val in list {
        if val < min { min = val; }
        if val > max { max = val; }
    }
    (min, max)
}

let data = [3, 7, 1, 9, 4];
let (lo, hi) = min_max(&data);
println!("min={}, max={}", lo, hi);

