// Simplified example. In real code, use Option<f64>
// to handle division by zero properly.
fn divide(a: f64, b: f64) -> f64 {
    if b == 0.0 {
        return 0.0;  // early return
    }
    a / b  // implicit return
}

fn main() {
    println!("10 / 3 = {}", divide(10.0, 3.0));
    println!("10 / 0 = {}", divide(10.0, 0.0));
}

